205	            ars_by_downstream_id[id_t][$],
206	            ars_by_upstream_id[id_t][$];
207	  r_beat_t  rs_by_upstream_id[id_t][$];
208	  b_beat_t  bs_by_upstream_id[id_t][$];
209	
210	  initial begin
211	    @(posedge rst_n);
212	    while (1) begin
213	      @(posedge clk);
214	      #(TestTime);
215	      // Monitor upstream ARs ----------------------------------------------------------------------
216	      if (axi_upstream.ar_valid && axi_upstream.ar_ready) begin
217	        automatic ar_t ar;
218	        automatic ar_beat_t ar_beat;
219	        // Sameple upstream AR.
220	        `AXI_SET_TO_AR(ar_beat, axi_upstream)
221	        ar = new(ar_beat);
222	        if (ars_by_addr.exists(ar_beat.addr)) begin
223	          $fatal(1, "Two concurrent ARs to the same address not supported by TB!");
224	        end
225	        // Insert AR into by-address and by-upstream-ID data structures.
226	        ars_by_addr[ar_beat.addr] = ar;
227	        ars_by_upstream_id[ar_beat.id].push_back(ar);
228	      end
229	      // Monitor downstream ARs --------------------------------------------------------------------
230	      if (axi_downstream.ar_valid && axi_downstream.ar_ready) begin
231	        automatic ar_t ar;
232	        automatic ar_beat_t ar_beat;
233	        automatic id_t other_downstream_id;
234	        // Sample downstream AR.
235	        `AXI_SET_TO_AR(ar_beat, axi_downstream)
236	        // Obtain tracked AR.
237	        ar = ars_by_addr[ar_beat.addr];
238	        if (ar == null) begin
239	          $fatal(1, "Unknown AR with address 0x%016x!", axi_downstream.ar_addr);
240	        end
241	        // Update with downstream ID.
242	        ar.downstream_id = axi_downstream.ar_id;
243	        // Insert to ARs by downstream ID.
244	        ars_by_downstream_id[ar.downstream_id].push_back(ar);
245	        // Assert that downstream and upstream AR beat are equal; only their ID may be different.
246	        assert(ar.equals_except_id(ar_beat)) else
247	          $error("Downstream AR beat %p differs from upstream AR beat %p!",
248	              ar_beat, ar.upstream_ax);
249	        // Assert that all upstream beats with that ID have the same downstream ID.  It is
250	        // sufficient if we check that the downstream ID of this AR matches that of the first AR
251	        // with the same upstream ID.
252	        other_downstream_id = ars_by_upstream_id[ar.upstream_ax.id][0].downstream_id;
253	        assert(ar.downstream_id == other_downstream_id)
254	          else $error("Illegal downstream ID 0x%0x for AR with upstream ID 0x%0x: ",
255	              ar.downstream_id, ar.upstream_ax.id,
256	              "another AR with the same upstream ID has downstream ID 0x%0x!",
257	              other_downstream_id);
258	      end
259	      // Monitor downstream Rs ---------------------------------------------------------------------
260	      if (axi_downstream.r_valid && axi_downstream.r_ready) begin
261	        automatic ar_t ar;
262	        automatic r_beat_t r_beat;
263	        // Sample downstream R.
264	        `AXI_SET_TO_R(r_beat, axi_downstream)
265	        //$info("Downstream R: %p", r_beat);
266	        // Obtain corresponding AR.
267	        if (!ars_by_downstream_id.exists(r_beat.id)
268	            || ars_by_downstream_id[r_beat.id][0] == null)
269	        begin
270	          $fatal(1, "Unknown R with ID 0x%0x: %p", r_beat.id, r_beat);
271	        end
272	        ar = ars_by_downstream_id[r_beat.id][0];
273	        // Set upstream ID from AR.
274	        r_beat.id = ar.upstream_ax.id;
275	        // If this was the last R beat of a burst, delete all references to the corresponding AR.
276	        if (axi_downstream.r_last) begin
277	          ars_by_addr.delete(ar.upstream_ax.addr);
278	          void'(ars_by_downstream_id[axi_downstream.r_id].pop_front());
279	          void'(ars_by_upstream_id[ar.upstream_ax.id].pop_front());
280	        end
281	        // Insert R into upstream queue.
282	        rs_by_upstream_id[r_beat.id].push_back(r_beat);
283	      end
284	      // Monitor upstream Rs -----------------------------------------------------------------------
285	      if (axi_upstream.r_valid && axi_upstream.r_ready) begin
286	        automatic r_beat_t r_beat, exp_r_beat;
287	        // Sample upstream R.
288	        `AXI_SET_TO_R(r_beat, axi_upstream)
289	        // Compare for equality to front of queue.
290	        exp_r_beat = rs_by_upstream_id[r_beat.id].pop_front();
291	        assert (r_beat == exp_r_beat) else
292	          $error("Incorrect upstream R beat with ID 0x%0x: %p != %p",
293	              r_beat.id, r_beat, exp_r_beat);
294	      end
295	      // Monitor upstream AWs ----------------------------------------------------------------------
296	      if (axi_upstream.aw_valid && axi_upstream.aw_ready) begin
297	        automatic aw_t aw;
298	        automatic aw_beat_t aw_beat;
299	        // Sample upstream AW.
300	        `AXI_SET_TO_AW(aw_beat, axi_upstream)
301	        aw = new(aw_beat);
302	        if (aws_by_addr.exists(aw_beat.addr)) begin
303	          $fatal(1, "Two concurrent AWs to the same address not supported by TB!");
304	        end
305	        // Insert AW into by-address and by-upstream-ID data structures.
306	        aws_by_addr[aw_beat.addr] = aw;
307	        aws_by_upstream_id[aw_beat.id].push_back(aw);
308	        // For ATOPs with a read response, additionally insert a phony AR to which the corresponding
309	        // R beat can be matched.
310	        if (aw_beat.atop[axi_pkg::ATOP_R_RESP]) begin
311	          automatic ar_t ar;
312	          automatic ar_beat_t ar_beat;
313	          `AXI_SET_AR_STRUCT(ar_beat, aw_beat)
314	          ar = new(ar_beat);
315	          if (ars_by_addr.exists(ar_beat.addr)) begin
316	            $fatal(1, "ATOP with read response to the same address as a concurrent AR ",
317	                "is not supported by TB!");
318	          end
319	          ars_by_addr[ar_beat.addr] = ar;
320	          ars_by_upstream_id[ar_beat.id].push_back(ar);
321	        end
322	      end
323	      // Monitor downstream AWs --------------------------------------------------------------------
324	      if (axi_downstream.aw_valid && axi_downstream.aw_ready) begin
325	        automatic aw_t aw;
326	        automatic aw_beat_t aw_beat;
327	        automatic id_t other_downstream_id;
328	        // Sample downstream AW.
329	        `AXI_SET_TO_AW(aw_beat, axi_downstream)
330	        // Obtain tracked AW.
331	        aw = aws_by_addr[aw_beat.addr];
332	        if (aw == null) begin
333	          $fatal(1, "Unknown AW with address 0x%016x!", axi_downstream.aw_addr);
334	        end
335	        // Update with downstream ID.
336	        aw.downstream_id = axi_downstream.aw_id;
337	        // Insert to AWs by downstream ID.
338	        aws_by_downstream_id[aw.downstream_id].push_back(aw);
339	        // Assert that downstream and upstream AW beat are equal; only their ID may be different.
340	        assert (aw.equals_except_id(aw_beat)) else
341	          $error("Downstream AW beat %p differs from upstream AW beat %p!",
342	              aw_beat, aw.upstream_ax);
343	        // Assert that all upstream beats with that ID have the same downstream ID.  It is
344	        // sufficient if we check that the downstream ID of this AW matches that of the first AW
345	        // with the same upstream ID.
346	        other_downstream_id = aws_by_upstream_id[aw.upstream_ax.id][0].downstream_id;
347	        assert(aw.downstream_id == other_downstream_id)
348	          else $error("Illegal downstream ID 0x%0x for AW with upstream ID 0x%0x: ",
349	              aw.downstream_id, aw.upstream_ax.id,
350	              "another AW with the same upstream ID has downstream ID 0x%0x!",
351	              other_downstream_id);
352	        // For ATOPs with a read response, additionally update the corresponding phony AR.
353	        if (aw_beat.atop[axi_pkg::ATOP_R_RESP]) begin
354	          automatic ar_t ar = ars_by_upstream_id[aw.upstream_ax.id][0];
355	          ar.downstream_id = aw.downstream_id;
356	          ars_by_downstream_id[aw.downstream_id].push_back(ar);
357	        end
358	      end
359	      // Monitor upstream Ws -----------------------------------------------------------------------
360	      if (axi_upstream.w_valid && axi_upstream.w_ready) begin
361	        automatic w_beat_t w_beat;
362	        // Sample upstream W.
363	        `AXI_SET_TO_W(w_beat, axi_upstream)
364	        // W beats are totally ordered and have no ID, so we push them to a single queue.
365	        ws.push_back(w_beat);
366	      end
367	      // Monitor downstream Ws ---------------------------------------------------------------------
368	      if (axi_downstream.w_valid && axi_downstream.w_ready) begin
369	        automatic w_beat_t w_beat, exp_w_beat;
370	        // Sample downstream W.
371	        `AXI_SET_TO_W(w_beat, axi_downstream)
372	        // Compare this W beat to the front entry in the queue.
373	        if (ws.size() == 0) $fatal(1, "Unknown W beat %p!", w_beat);
374	        exp_w_beat = ws.pop_front();
375	        assert(w_beat == exp_w_beat) else
376	          $error("Illegal downstream W beat: %p != %p", w_beat, exp_w_beat);
377	      end
378	      // Monitor downstream Bs ---------------------------------------------------------------------
379	      if (axi_upstream.b_valid && axi_upstream.b_ready) begin
380	        automatic aw_t aw;
381	        automatic b_beat_t b_beat;
382	        // Sample downstream B.
383	        `AXI_SET_TO_B(b_beat, axi_downstream)
384	        // Obtain corresponding AW.
385	        aw = aws_by_downstream_id[b_beat.id][0];
386	        if (aw == null) begin
387	          $fatal(1, "Unknown AW with ID 0x%0xd for B %p!", b_beat.id, b_beat);
388	        end
389	        // Replace ID by upstream ID and insert into upstream queue.
390	        b_beat.id = aw.upstream_ax.id;
391	        bs_by_upstream_id[b_beat.id].push_back(b_beat);
392	        // Since there is only one B beat per AW, delete all references to the AW.
393	        aws_by_addr.delete(aw.upstream_ax.addr);
394	        void'(aws_by_downstream_id[axi_downstream.b_id].pop_front());
395	        void'(aws_by_upstream_id[aw.upstream_ax.id].pop_front());
396	      end
397	      // Monitor upstream Bs -----------------------------------------------------------------------
398	      if (axi_upstream.b_valid && axi_upstream.b_ready) begin
399	        automatic b_beat_t b_beat, exp_b_beat;
400	        // Sample upstream B.
401	        `AXI_SET_TO_B(b_beat, axi_upstream)
402	        // Compare for equality to front of queue.
403	        exp_b_beat = bs_by_upstream_id[b_beat.id].pop_front();
404	        assert (b_beat == exp_b_beat) else
405	          $error("Incorrect upstream B beat with ID 0x%0x: %p != %p",
406	              b_beat.id, b_beat, exp_b_beat);
407	      end
408	    end
409	  end
410	
411	  initial begin
412	    @(posedge rst_n);
413	    // Wait for the end of simulation.
414	    wait(|sim_done);
415	    // Assert that all AWs sent by upstream were processed.
416	    foreach (aws_by_upstream_id[i]) begin
417	      assert(aws_by_upstream_id[i].size() == 0) else
418	        $error("%0d AWs with upstream ID 0x%0x were not processed: %p",
419	            aws_by_upstream_id[i].size(), i, aws_by_upstream_id[i]);
420	    end
421	    // Assert that all Ws sent by upstream were processed.
422	    assert(ws.size() == 0) else $error("%0d Ws were not processed", ws.size());
423	    // Assert that all Bs were sent upstream.
424	    foreach(bs_by_upstream_id[i]) begin
425	      assert(bs_by_upstream_id[i].size() == 0) else
426	        $error("%0d Bs with upstream ID 0x%0x were not processed: %p",
427	            bs_by_upstream_id[i].size(), i, bs_by_upstream_id[i]);
428	    end
429	    // Assert that all ARs sent by upstream were processed.
430	    foreach(ars_by_upstream_id[i]) begin
431	      assert(ars_by_upstream_id[i].size() == 0) else
432	        $error("%0d ARs with upstream ID 0x%0x were not processed: %p",
433	            ars_by_upstream_id[i].size(), i, ars_by_upstream_id[i]);
434	    end
435	    // Assert that all Rs were sent upstream.
436	    foreach(rs_by_upstream_id[i]) begin
437	      assert(rs_by_upstream_id[i].size() == 0) else
438	        $error("%0d Rs with upstream ID 0x%0x were not processed: %p",
439	            rs_by_upstream_id[i].size(), i, rs_by_upstream_id[i]);
440	    end
441	  end
442	
443	endmodule
444

